// Get or create the writing project
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const projectTitle = $('workflow_trigger').first().json.project_title;
const genreSlug = $('workflow_trigger').first().json.genre_slug;

// Try to find the project (includes outline)
let project = null;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/writing_projects?title=eq.' + encodeURIComponent(projectTitle) + '&limit=1',
    headers: headers
  });
  const projects = Array.isArray(resp) ? resp : [resp];
  if (projects.length > 0 && projects[0]?.id) {
    project = projects[0];
  }
} catch (e) {}

// Create project if not found
if (!project) {
  try {
    const created = await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/writing_projects',
      headers: { ...headers, 'Prefer': 'return=representation' },
      body: { title: projectTitle, genre_slug: genreSlug, project_type: 'book', status: 'in_progress', chapter_count: 0 }
    });
    project = Array.isArray(created) ? created[0] : created;
  } catch (e) {
    project = { id: null, title: projectTitle };
  }
}

// Fetch story bible entries
let storyBible = [];
if (project?.id) {
  try {
    const bibleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/story_bible?project_id=eq.' + project.id + '&order=chapter_introduced,entry_type,name',
      headers: headers
    });
    storyBible = Array.isArray(bibleResp) ? bibleResp : [];
  } catch (e) {}
}

// Fetch writing samples
let samplesText = 'No writing samples available.';
try {
  const listResp = await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/storage/v1/object/list/author-content',
    headers: headers,
    body: { prefix: 'writing-samples', limit: 20 }
  });
  const files = (listResp || []).filter(f => f.name && f.name !== '.gitkeep' && f.metadata?.size > 0);
  if (files.length > 0) {
    const samples = [];
    for (const file of files.slice(0, 5)) {
      try {
        const content = await this.helpers.httpRequest({
          method: 'GET',
          url: supabaseUrl + '/storage/v1/object/author-content/writing-samples/' + file.name,
          headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey },
          encoding: 'utf-8',
          json: false
        });
        samples.push(typeof content === 'string' ? content : JSON.stringify(content));
      } catch (e) {}
    }
    if (samples.length > 0) samplesText = samples.join('\n\n');
  }
} catch (e) {}

return [{ json: { project: project, story_bible: storyBible, writing_samples: samplesText, outline: project?.outline || null } }];

const trigger = $('workflow_trigger').first().json;
const genre = $('get_genre_config').first().json;
const genreData = Array.isArray(genre) ? genre[0] : genre;
const research = $('research_topic').first().json.message || '';
const projectData = $('get_project_data').first().json;
const storyBible = projectData.story_bible || [];
const writingSamples = projectData.writing_samples || '';

// Auto-load outline: use trigger.outline if provided, otherwise fall back to stored outline
const storedOutline = projectData.outline;
let outlineText = trigger.outline || '';

if (!outlineText && storedOutline) {
  // Format the stored JSON outline into readable text for the prompt
  if (typeof storedOutline === 'object') {
    const parts = [];
    if (storedOutline.premise) parts.push('PREMISE: ' + storedOutline.premise);
    if (storedOutline.themes) parts.push('THEMES: ' + storedOutline.themes.join(', '));
    if (storedOutline.characters) {
      parts.push('CHARACTERS:\n' + storedOutline.characters.map(c => 
        '- ' + c.name + ' (' + c.role + '): ' + c.arc + (c.description ? ' — ' + c.description : '')
      ).join('\n'));
    }
    if (storedOutline.chapters) {
      parts.push('CHAPTER OUTLINE:\n' + storedOutline.chapters.map(ch => 
        'Ch ' + ch.number + ' — ' + ch.title + ': ' + ch.brief + (ch.arc_notes ? ' [Arc: ' + ch.arc_notes + ']' : '')
      ).join('\n'));
    }
    outlineText = parts.join('\n\n');
  } else {
    outlineText = String(storedOutline);
  }
}

// Format story bible for the prompt
const bibleText = storyBible.length > 0
  ? storyBible.map(e => '[' + e.entry_type + '] ' + e.name + ': ' + e.description + ' (ch' + e.chapter_introduced + (e.last_chapter_seen > e.chapter_introduced ? '-ch' + e.last_chapter_seen : '') + ')').join('\n')
  : 'No story bible entries yet (this is likely the first chapter).';

const chapterNum = parseInt(trigger.chapter_number);

// If we have a stored outline, extract this specific chapter's details
let chapterBrief = trigger.brief || '';
let chapterResearchTopics = '';
if (storedOutline?.chapters && !trigger.brief) {
  const thisChapter = storedOutline.chapters.find(ch => ch.number === chapterNum);
  if (thisChapter) {
    chapterBrief = thisChapter.brief + (thisChapter.arc_notes ? '\nArc notes: ' + thisChapter.arc_notes : '');
    if (thisChapter.research_topics) chapterResearchTopics = thisChapter.research_topics.join(', ');
  }
}

const prompt = 'You are a world-class novelist writing Chapter ' + chapterNum + ' of "' + trigger.project_title + '", a ' + (genreData?.genre_name || 'fiction') + ' novel.\n\n## Genre Guidelines\n' + (genreData?.writing_guidelines || '') + '\n\n## Writing Style Reference\n' + writingSamples + '\n\n## Research\n' + research + '\n\n## Story Bible (established canon - DO NOT contradict)\n' + bibleText + '\n\n## Book Outline\n' + (outlineText || 'No outline provided.') + '\n\n## This Chapter\'s Brief\n' + (chapterBrief || trigger.brief || 'No specific brief provided.') + '\n\n## Requirements\n- Maintain consistency with all story bible entries above\n- Internal character arc within this chapter\n- End on a compelling hook for the next chapter\n- Track character development and relationships\n- 3000-5000 words\n- Include natural scene breaks (---)\n- Reference established locations, characters, and plot threads where relevant\n\n## Output Format\nReturn JSON with these fields:\n- chapter_title: title for this chapter\n- chapter_text: the full chapter text\n- word_count: approximate word count\n- chapter_summary: 2-3 sentence summary of what happens\n- next_chapter_notes: suggestions for what should happen next\n- new_story_bible_entries: array of new entries to add [{entry_type, name, description}] where entry_type is one of: character, location, plot_thread, item, event';

return [{ json: { prompt: prompt, project_id: projectData.project?.id } }];

// Update story bible with new entries from this chapter
const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const projectId = $('build_chapter_prompt').first().json.project_id;
const chapterNum = parseInt($('workflow_trigger').first().json.chapter_number);
const output = $input.first().json.output || {};
const newEntries = output.new_story_bible_entries || [];

// Insert new story bible entries
if (newEntries.length > 0 && projectId) {
  try {
    const entries = newEntries.map(e => ({
      entry_type: e.entry_type,
      name: e.name,
      description: e.description,
      project_id: projectId,
      chapter_introduced: chapterNum,
      last_chapter_seen: chapterNum
    }));
    await this.helpers.httpRequest({
      method: 'POST',
      url: supabaseUrl + '/rest/v1/story_bible',
      headers: headers,
      body: entries
    });
  } catch (e) {}
}

// Update project chapter count
if (projectId) {
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: supabaseUrl + '/rest/v1/writing_projects?id=eq.' + projectId,
      headers: headers,
      body: { chapter_count: chapterNum, status: 'in_progress', updated_at: new Date().toISOString() }
    });
  } catch (e) {}
}

return [{ json: { output: output, project_id: projectId } }];

