const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/published_content',
    headers,
    body: {
      title: ($('update_story_bible').first().json.output?.chapter_title || 'Chapter ' + $('workflow_trigger').first().json.chapter_number),
      content_type: 'chapter',
      genre_slug: $('workflow_trigger').first().json.genre_slug,
      content_text: ($('update_story_bible').first().json.output?.chapter_text || ''),
      storage_path: $json.Key || '',
      project_id: $('build_chapter_prompt').first().json.project_id || null,
      chapter_number: parseInt($('workflow_trigger').first().json.chapter_number) || null,
      status: 'draft'
    }
  });
} catch (e) {
  // Don't fail the workflow if draft insert fails
}

return $input.all();
